// Helper: compute month-over-month change for a cluster
export function getTrend(clusterId: number): number {
  const n = monthlyTrends.length;
  if (n < 2) return 0;
  const last = monthlyTrends[n - 1].volumes[clusterId];
  const prev = monthlyTrends[n - 2].volumes[clusterId];
  if (prev === 0) return 0;
  return Math.round(((last - prev) / prev) * 100);
}
